onClick:
{{
  (() => {
// 1. Sinaliza atividade para o sistema de segurança (reseta os 15 min)
 JSutils.resetInactivityTimer();		
// 2 - Definimos os dados que vêm dos inputs do seu formulário/container
		const formData = {
	clinica001_id:			(InputID.text),
	clinica001_nome: 		(InputNome.text).trim().toUpperCase(),
	clinica001_endereco: 	(InputEndereco.text).trim().toUpperCase(),
	clinica001_bairro:   	(InputBairro.text).trim().toUpperCase(),
	clinica001_numero:   	(InputNumero.text).trim().toUpperCase(),
	clinica001_complemento:	(InputComplemento.text).trim().toUpperCase(),
	clinica001_cidade:      (InputCidade.text).trim().toUpperCase(),
	clinica001_email:       (InputEmail.text).trim().toLowerCase(),
	clinica001_telefone:	(InputTelefone.text).trim().toUpperCase().toString().replace(/\D/g, ""),
	clinica001_celular:     (InputCelular.text).trim().toUpperCase().toString().replace(/\D/g, ""),
	clinica001_uf:          (SelectUF.selectedOptionValue).trim().toUpperCase(),
	clinica001_comissao:	"0",
	clinica001_contato:		(InputContato.text).trim().toUpperCase(),
	clinica001_cep:			(InputCep.text).trim().toUpperCase().toString().replace(/\D/g, "")
    };

    if (appsmith.store.modalContexto?.acaoTipo === "ADICIONAR") {
      return JSconfirmation.showModal({
        action: "Insert",
        message: "Deseja salvar este novo registro?",
        icon: "plus",
        color: "green",
				row: formData
      });
    } else {
      return JSconfirmation.showModal({
        action: "Update",
        message: "Deseja salvar as alterações deste registro?",
        icon: "edit",
        color: "orange",
		    row: formData
      });
    }
  })()
}}
